oxy_webhelp_navlinks = {"ri_reports-d30753e44605":{"topics":[{"title":"Viewing anomaly reports","shortdesc":"<p class=\"shortdesc\">Anomaly reports contain information about anomaly snapshots and object anomalies         captured by <span class=\"ph\">Data Threat Analytics<\/span>.<\/p>","href":"saas\/viewing_anomaly_reports.html","attributes":{"data-id":"viewing_anomaly_reports"},"menu":{"hasChildren":false},"tocID":"viewing_anomaly_reports-d30753e44620","topics":[]},{"title":"<span class=\"ph\">Anomaly Detection<\/span> report details","shortdesc":"<p class=\"shortdesc\">The <span class=\"ph\">Anomaly Detection<\/span> report provides information about scanned and unscannable         objects. You can download a CSV or PDF file of the report or save a copy of the         report.<\/p>","href":"saas\/anomaly_detection_report_details.html","attributes":{"data-id":"anomaly_detection_report_details"},"menu":{"hasChildren":false},"tocID":"anomaly_detection_report_details-d30753e44634","topics":[]},{"title":"Anomaly report filters","shortdesc":"<p class=\"shortdesc\">You can use the anomaly report filters in the Anomaly Detection Details Report to         investigate anomalies. These filters help you perform a more granular analysis of         events.<\/p>","href":"saas\/anomaly_report_filters.html","attributes":{"data-id":"anomaly_report_filters"},"menu":{"hasChildren":false},"tocID":"anomaly_report_filters-d30753e44650","topics":[]},{"title":"Anomaly Detection Compliance Report","shortdesc":"<p class=\"shortdesc\">The Anomaly Detection Compliance Report provides visibility into <span class=\"ph\">Anomaly Detection<\/span> coverage by showing which objects were scanned, which were not, and         why.<\/p>","href":"saas\/anomaly_compliance_report.html","attributes":{"data-id":"anomaly_compliance_report"},"menu":{"hasChildren":false},"tocID":"anomaly_compliance_report-d30753e44661","next":"anomaly_compliance_report-d30753e44661"}]}};